import React, { useState, useEffect } from "react";
import Nav from "../Nav/Nav";
import Hero from "../Hero/Hero";
import { VideoCard } from "../Cinema/VideoCard";
import "./NewReservation.css";

function NewReservation() {
  const [cinemas, setCinemas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCinema, setSelectedCinema] = useState(null);
  const [selectedMovie, setSelectedMovie] = useState(null);
  const [selectedSlots, setSelectedSlots] = useState([]);
  const [currentStep, setCurrentStep] = useState(1);
  const [customerInfo, setCustomerInfo] = useState({
    customer_name: '',
    customer_email: '',
    customer_phone: '',
    company_name: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [validationErrors, setValidationErrors] = useState({
    email: '',
    phone: ''
  });
  const [cinemaSearchTerm, setCinemaSearchTerm] = useState('');

  // Validation functions
  const validateEmail = (email) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!email) {
      return 'Email is required';
    }
    if (!emailRegex.test(email)) {
      return 'Please enter a valid email address';
    }
    return '';
  };

  const validatePhone = (phone) => {
    // Remove all non-digit characters
    const cleanPhone = phone.replace(/\D/g, '');
    
    if (!phone) {
      return 'Phone number is required';
    }
    
    // Check for Sri Lankan phone number formats
    // +94XXXXXXXXX (12 digits) or 0XXXXXXXXX (10 digits)
    if (cleanPhone.length === 12 && cleanPhone.startsWith('94')) {
      return ''; // Valid +94 format
    } else if (cleanPhone.length === 10 && cleanPhone.startsWith('0')) {
      return ''; // Valid 0XXXXXXXXX format
    } else {
      return 'Please enter a valid Sri Lankan phone number (0XXXXXXXXX or +94XXXXXXXXX)';
    }
  };

  const handleEmailChange = (e) => {
    const email = e.target.value;
    setCustomerInfo({...customerInfo, customer_email: email});
    setValidationErrors({...validationErrors, email: validateEmail(email)});
  };

  const handlePhoneChange = (e) => {
    const phone = e.target.value;
    setCustomerInfo({...customerInfo, customer_phone: phone});
    setValidationErrors({...validationErrors, phone: validatePhone(phone)});
  };

  // Filter cinemas based on search term
  const filteredCinemas = cinemas.filter(cinema => 
    cinema.cinema_name.toLowerCase().includes(cinemaSearchTerm.toLowerCase()) ||
    cinema.cinema_location.toLowerCase().includes(cinemaSearchTerm.toLowerCase())
  );

  useEffect(() => {
    const fetchCinemas = async () => {
      try {
        const response = await fetch('http://localhost:5000/api/cinemas');
        const data = await response.json();
        
        if (data.success) {
          setCinemas(data.data);
        } else {
          console.error('Error fetching cinemas:', data.message);
        }
      } catch (error) {
        console.error('Error fetching cinemas:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchCinemas();
  }, []);

  const handleCinemaSelect = (cinema) => {
    setSelectedCinema(cinema);
    setCurrentStep(2);
  };

  const handleMovieSelect = (movie) => {
    setSelectedMovie(movie);
    setCurrentStep(3);
  };

  const handleSlotSelect = (slot) => {
    setSelectedSlots(prev => {
      const existingIndex = prev.findIndex(s => s.slot_id === slot.slot_id);
      if (existingIndex >= 0) {
        return prev.filter((_, index) => index !== existingIndex);
      } else {
        return [...prev, slot];
      }
    });
  };

  const calculateTotal = () => {
    return selectedSlots.reduce((total, slot) => total + slot.price, 0);
  };

  // New function to calculate advertisement details
  const calculateAdvertisementDetails = () => {
    if (!selectedMovie || selectedSlots.length === 0) return null;
    
    const currentDate = new Date();
    const movieEndDate = new Date(selectedMovie.end_date);
    const timeDiff = movieEndDate.getTime() - currentDate.getTime();
    const daysDiff = Math.ceil(timeDiff / (1000 * 3600 * 24));
    
    const dailySlotCost = calculateTotal();
    const totalCost = dailySlotCost * daysDiff;
    
    return {
      startDate: currentDate,
      endDate: movieEndDate,
      days: daysDiff,
      dailySlotCost: dailySlotCost,
      totalCost: totalCost
    };
  };

  const handleConfirmReservation = async () => {
    try {
      setIsSubmitting(true);

      // Re-validate all fields before final submission
      const emailError = validateEmail(customerInfo.customer_email);
      const phoneError = validatePhone(customerInfo.customer_phone);

      if (!customerInfo.customer_name || !customerInfo.company_name || emailError || phoneError) {
        setValidationErrors({
          email: emailError,
          phone: phoneError
        });
        alert('Please fill in all required fields correctly.');
        setIsSubmitting(false);
        return;
      }

      const reservationData = {
        cinema_id: selectedCinema._id,
        movie_name: selectedMovie.name,
        movie_key: selectedMovie.key,
        show_date: new Date().toISOString().split('T')[0],
        show_time: new Date().toTimeString().split(' ')[0].substring(0, 5),
        customer_info: customerInfo,
        advertisement_slots: selectedSlots.map(slot => ({
          slot_id: slot.slot_id,
          slot_type: slot.slot_type,
          slot_number: parseInt(slot.slot_number),
          price: slot.price
        }))
      };

      console.log('Sending reservation data:', reservationData);
      console.log('Selected slots:', selectedSlots);

      const response = await fetch('http://localhost:5000/api/reservations', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(reservationData),
      });

      const result = await response.json();
      console.log('Backend response:', result);

      if (result.success) {
        alert('Reservation confirmed successfully!');
        // Reset form
        setSelectedCinema(null);
        setSelectedMovie(null);
        setSelectedSlots([]);
        setCurrentStep(1);
        setCustomerInfo({
          customer_name: '',
          customer_email: '',
          customer_phone: '',
          company_name: ''
        });
        setValidationErrors({
          email: '',
          phone: ''
        });
      } else {
        alert(`Error: ${result.message}`);
      }
    } catch (error) {
      console.error('Error creating reservation:', error);
      alert('An error occurred while creating the reservation. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDownloadDetails = () => {
    // Create HTML content for PDF
    const htmlContent = `
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="utf-8">
        <title>Reservation Details</title>
        <style>
          body {
            font-family: Arial, sans-serif;
            margin: 20px;
            color: #333;
          }
          .header {
            text-align: center;
            border-bottom: 3px solid #e63946;
            padding-bottom: 20px;
            margin-bottom: 30px;
          }
          .header h1 {
            color: #e63946;
            margin: 0;
            font-size: 28px;
          }
          .header p {
            color: #666;
            margin: 5px 0 0 0;
            font-size: 16px;
          }
          .section {
            margin-bottom: 25px;
          }
          .section h2 {
            color: #282c34;
            border-bottom: 2px solid #61dafb;
            padding-bottom: 5px;
            margin-bottom: 15px;
          }
          .info-row {
            display: flex;
            margin-bottom: 10px;
            padding: 8px 0;
          }
          .info-label {
            font-weight: bold;
            width: 120px;
            color: #282c34;
          }
          .info-value {
            flex: 1;
            color: #333;
          }
          .slots-table {
            width: 100%;
            border-collapse: collapse;
            margin: 15px 0;
          }
          .slots-table th,
          .slots-table td {
            border: 1px solid #ddd;
            padding: 12px;
            text-align: left;
          }
          .slots-table th {
            background-color: #f7f7f7;
            font-weight: bold;
            color: #282c34;
          }
          .total-section {
            background-color: #e63946;
            color: white;
            padding: 20px;
            border-radius: 8px;
            text-align: center;
            margin-top: 30px;
          }
          .total-section h3 {
            margin: 0 0 10px 0;
            font-size: 24px;
          }
          .total-section .amount {
            font-size: 32px;
            font-weight: bold;
          }
          .footer {
            text-align: center;
            margin-top: 40px;
            padding-top: 20px;
            border-top: 1px solid #ddd;
            color: #666;
          }
        </style>
      </head>
      <body>
        <div class="header">
          <h1>D&S Creations</h1>
          <p>Advertisement Slot Reservation</p>
        </div>

        <div class="section">
          <h2>Reservation Details</h2>
          <div class="info-row">
            <div class="info-label">Cinema:</div>
            <div class="info-value">${selectedCinema?.cinema_name}</div>
          </div>
          <div class="info-row">
            <div class="info-label">Location:</div>
            <div class="info-value">${selectedCinema?.cinema_location}</div>
          </div>
          <div class="info-row">
            <div class="info-label">Movie:</div>
            <div class="info-value">${selectedMovie?.name}</div>
          </div>
          <div class="info-row">
            <div class="info-label">Date:</div>
            <div class="info-value">${new Date().toLocaleDateString()}</div>
          </div>
          <div class="info-row">
            <div class="info-label">Time:</div>
            <div class="info-value">${new Date().toLocaleTimeString()}</div>
          </div>
        </div>

        <div class="section">
          <h2>Selected Advertisement Slots</h2>
          <table class="slots-table">
            <thead>
              <tr>
                <th>Slot Type</th>
                <th>Slot Number</th>
                <th>Price (LKR)</th>
              </tr>
            </thead>
            <tbody>
              ${selectedSlots.map(slot => `
                <tr>
                  <td>${slot.slot_type.charAt(0).toUpperCase() + slot.slot_type.slice(1)}</td>
                  <td>${slot.slot_number}</td>
                  <td>${slot.price.toLocaleString()}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>
        </div>

        <div class="section">
          <h2>Advertisement Period Calculation</h2>
          ${(() => {
            const adDetails = calculateAdvertisementDetails();
            if (!adDetails) return '<p>No advertisement details available</p>';
            
            return `
              <div class="info-row">
                <div class="info-label">Period:</div>
                <div class="info-value">${adDetails.startDate.toLocaleDateString()} to ${adDetails.endDate.toLocaleDateString()}</div>
              </div>
              <div class="info-row">
                <div class="info-label">Duration:</div>
                <div class="info-value">${adDetails.days} days</div>
              </div>
              <div class="info-row">
                <div class="info-label">Daily:</div>
                <div class="info-value">LKR ${adDetails.dailySlotCost.toLocaleString()}</div>
              </div>
              <div class="info-row">
                <div class="info-label">Calculation:</div>
                <div class="info-value">LKR ${adDetails.dailySlotCost.toLocaleString()} × ${adDetails.days} days</div>
              </div>
            `;
          })()}
        </div>

        <div class="total-section">
          <h3>Sub Total</h3>
          <div class="amount">LKR ${(() => {
            const adDetails = calculateAdvertisementDetails();
            return adDetails ? adDetails.totalCost.toLocaleString() : calculateTotal().toLocaleString();
          })()}</div>
        </div>

        <div class="footer">
          <p>Thank you for choosing D&S Creations!</p>
          <p>For inquiries, please contact us at info@dscreations.com</p>
        </div>
      </body>
      </html>
    `;

    // Create a new window and print the content
    const printWindow = window.open('', '_blank');
    printWindow.document.write(htmlContent);
    printWindow.document.close();
    
    // Wait for content to load, then trigger print
    printWindow.onload = function() {
      printWindow.print();
    };
  };

  return (
    <div>
      {/* Navbar */}
      <Nav />

      {/* Hero Section */}
      <Hero 
        title="BOOK"
        subtitle="SLOTS"
        backgroundVideo="https://www.youtube.com/watch?v=f1Ntb6hJDQU"
        backgroundImage="https://images.unsplash.com/photo-1489599808426-7b0a4a0a0a0a?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=2070&q=80"
        scrollTarget="#reservation-form"
        typingStrings={["ADVERTISE", "PROMOTE", "MARKET"]}
      />

      <section id="reservation-form" className="reservation-section">
        <div className="container">
          {/* Step Navigation */}
          <div className="step-navigation">
            <div className={`step ${currentStep >= 1 ? 'active' : ''}`}>
              <div className="step-number">1</div>
              <div className="step-label">Select Cinema</div>
            </div>
            <div className={`step ${currentStep >= 2 ? 'active' : ''}`}>
              <div className="step-number">2</div>
              <div className="step-label">Select Movie</div>
            </div>
            <div className={`step ${currentStep >= 3 ? 'active' : ''}`}>
              <div className="step-number">3</div>
              <div className="step-label">Select Slots</div>
            </div>
            <div className={`step ${currentStep >= 4 ? 'active' : ''}`}>
              <div className="step-number">4</div>
              <div className="step-label">Confirm</div>
            </div>
          </div>

          {/* Step 1: Select Cinema */}
          {currentStep === 1 && (
            <div>
              <h2>Step 1: Select Cinema</h2>
              {loading ? (
                <div className="loading-message">
                  <p>Loading cinemas...</p>
                </div>
              ) : (
                <div className="cinemas-grid">
                  <div className="cinema-search-container">
                    <h3>Available Cinemas ({filteredCinemas.length})</h3>
                    <div className="search-box">
                      <i className="fa fa-search"></i>
                      <input
                        type="text"
                        placeholder="Search cinemas by name or location..."
                        value={cinemaSearchTerm}
                        onChange={(e) => setCinemaSearchTerm(e.target.value)}
                        className="cinema-search-input"
                      />
                      {cinemaSearchTerm && (
                        <button 
                          className="clear-search-btn"
                          onClick={() => setCinemaSearchTerm('')}
                          title="Clear search"
                        >
                          <i className="fa fa-times"></i>
                        </button>
                      )}
                    </div>
                  </div>
                  <div className="cinema-cards">
                    {filteredCinemas.length === 0 ? (
                      <div className="no-results">
                        <i className="fa fa-search"></i>
                        <h4>No cinemas found</h4>
                        <p>Try adjusting your search terms</p>
                      </div>
                    ) : (
                      filteredCinemas.map((cinema) => (
                        <div key={cinema._id} className="cinema-card">
                          <div className="cinema-header">
                            <h4>{cinema.cinema_name}</h4>
                            <span className="cinema-location">{cinema.cinema_location}</span>
                          </div>
                          <div className="cinema-details">
                            <div className="contact-item">
                              <i className="fa fa-phone"></i>
                              <span>+94 11 234 5678</span>
                            </div>
                            <div className="contact-item">
                              <i className="fa fa-envelope"></i>
                              <span>info@cineplexcolombo.com</span>
                            </div>
                          </div>
                          <button 
                            className="select-cinema-btn"
                            onClick={() => handleCinemaSelect(cinema)}
                          >
                            Select Cinema
                          </button>
                        </div>
                      ))
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Step 2: Select Movie */}
          {currentStep === 2 && selectedCinema && (
            <div>
              <h2>Step 2: Select Movie</h2>
              <div className="selected-cinema-info">
                <h3>Selected Cinema: {selectedCinema.cinema_name}</h3>
                <p><strong>Location:</strong> {selectedCinema.cinema_location}</p>
              </div>
              <div className="movie-grid">
                <h3>Available Movies:</h3>
                {Object.entries(selectedCinema.ongoing_movies || {}).map(([key, movie]) => (
                  <VideoCard
                    key={key}
                    video={{
                      ...movie,
                      slotInfo: selectedCinema.movie_slot_pricing?.[key],
                      startDate: movie.start_date,
                      endDate: movie.end_date
                    }}
                    onSelect={() => handleMovieSelect({ ...movie, key })}
                  />
                ))}
              </div>
              <div className="step-navigation">
                <button className="btn-secondary" onClick={() => setCurrentStep(1)}>Back to Cinemas</button>
              </div>
            </div>
          )}

          {/* Step 3: Select Slots */}
          {currentStep === 3 && selectedMovie && (
            <div>
              <h2>Step 3: Select Advertisement Slots</h2>
              <div className="selected-movie-info">
                <h3>Cinema: {selectedCinema.cinema_name}</h3>
                <h3>Movie: {selectedMovie.name}</h3>
              </div>
              
              <div className="compact-slots-selection">
                {selectedCinema.movie_slot_pricing?.[selectedMovie.key]?.slots?.map((slot) => (
                  <div key={slot._id} className="slot-card">
                    <div className="slot-card-header">
                      <h4>{slot.slot_type.charAt(0).toUpperCase() + slot.slot_type.slice(1)}</h4>
                      <span className="slot-count">5 of 5 available</span>
                    </div>
                    <div className="slot-card-content">
                      <div 
                        className={`compact-slot-item ${selectedSlots.some(s => s.slot_id === slot._id) ? 'selected' : ''}`}
                        onClick={() => handleSlotSelect({
                          slot_id: slot._id,
                          slot_type: slot.slot_type,
                          slot_number: slot.slot_number,
                          price: slot.price
                        })}
                      >
                        <span className="slot-number">{slot.slot_number}</span>
                        <span className="slot-price">LKR {slot.price.toLocaleString()}</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              {/* Advertisement Calculation */}
              {(() => {
                const adDetails = calculateAdvertisementDetails();
                if (!adDetails) return null;
                
                return (
                  <div className="advertisement-calculation">
                    <h4>Advertisement Period Calculation</h4>
                    <div className="calculation-details">
                      <p>The advertisement runs for <strong>{adDetails.startDate.toLocaleDateString()}</strong> to <strong>{adDetails.endDate.toLocaleDateString()}</strong> totally for <strong>{adDetails.days}</strong> days totally costs <strong>LKR {adDetails.dailySlotCost.toLocaleString()} × {adDetails.days} days</strong> = <span className="total-calculation">LKR {adDetails.totalCost.toLocaleString()}</span></p>
                    </div>
                  </div>
                );
              })()}

              <div className="step-navigation">
                <button className="btn-secondary" onClick={() => setCurrentStep(2)}>Back</button>
                <button 
                  className="btn-primary" 
                  disabled={selectedSlots.length === 0}
                  onClick={() => setCurrentStep(4)}
                >
                  Continue to Confirmation
                </button>
              </div>
            </div>
          )}

          {/* Step 4: Confirmation */}
          {currentStep === 4 && (
            <div>
              <h2>Step 4: Confirmation</h2>
              
              <div className="confirmation-summary">
                <h3>Reservation Summary</h3>
                <div className="reservation-details">
                  <p><strong>Cinema:</strong> {selectedCinema.cinema_name}</p>
                  <p><strong>Location:</strong> {selectedCinema.cinema_location}</p>
                  <p><strong>Movie:</strong> {selectedMovie.name}</p>
                </div>

                <div className="selected-slots-details">
                  <h4>Selected Slots:</h4>
                  {selectedSlots.map((slot, index) => (
                    <div key={index} className="slot-detail">
                      <span>{slot.slot_type.charAt(0).toUpperCase() + slot.slot_type.slice(1)} Slot {slot.slot_number} - LKR {slot.price.toLocaleString()}</span>
                    </div>
                  ))}
                </div>

                {/* Advertisement Calculation */}
                {(() => {
                  const adDetails = calculateAdvertisementDetails();
                  if (!adDetails) return null;
                  
                  return (
                    <div className="advertisement-calculation">
                      <h4>Advertisement Period Calculation</h4>
                      <div className="calculation-details">
                        <p>Advertisement runs from: <strong>{adDetails.startDate.toLocaleDateString()}</strong> to <strong>{adDetails.endDate.toLocaleDateString()}</strong></p>
                        <p>Total period: <strong>{adDetails.days}</strong> days</p>
                        <p>Daily slot cost: <strong>LKR {adDetails.dailySlotCost.toLocaleString()} × {adDetails.days} days</strong></p>
                        <p className="total-calculation">Total Cost: <strong>LKR {adDetails.totalCost.toLocaleString()}</strong></p>
                      </div>
                    </div>
                  );
                })()}

                <div className="customer-info-form">
                  <h4>Customer Information</h4>
                  <div className="form-row">
                    <div className="form-group">
                      <label htmlFor="customer_name">Full Name *</label>
                      <input
                        type="text"
                        id="customer_name"
                        value={customerInfo.customer_name}
                        onChange={(e) => setCustomerInfo({...customerInfo, customer_name: e.target.value})}
                        required
                      />
                    </div>
                    <div className="form-group">
                      <label htmlFor="company_name">Company Name *</label>
                      <input
                        type="text"
                        id="company_name"
                        value={customerInfo.company_name}
                        onChange={(e) => setCustomerInfo({...customerInfo, company_name: e.target.value})}
                        required
                      />
                    </div>
                  </div>
                  <div className="form-row">
                    <div className={`form-group ${validationErrors.email ? 'error' : customerInfo.customer_email ? 'success' : ''}`}>
                      <label htmlFor="customer_email">Email *</label>
                      <input
                        type="email"
                        id="customer_email"
                        value={customerInfo.customer_email}
                        onChange={handleEmailChange}
                        required
                      />
                      {validationErrors.email && <p className="error-message">{validationErrors.email}</p>}
                    </div>
                    <div className={`form-group ${validationErrors.phone ? 'error' : customerInfo.customer_phone ? 'success' : ''}`}>
                      <label htmlFor="customer_phone">Phone Number *</label>
                      <input
                        type="tel"
                        id="customer_phone"
                        value={customerInfo.customer_phone}
                        onChange={handlePhoneChange}
                        placeholder="0XXXXXXXXX or +94XXXXXXXXX"
                        required
                      />
                      {validationErrors.phone && <p className="error-message">{validationErrors.phone}</p>}
                    </div>
                  </div>
                </div>

                <div className="step-navigation">
                  <button className="btn-secondary" onClick={() => setCurrentStep(3)}>Back to Slots</button>
                  <button className="btn-download" onClick={handleDownloadDetails}>Download Details</button>
                  <button 
                    className="confirm-reservation-btn"
                    onClick={handleConfirmReservation}
                    disabled={isSubmitting}
                  >
                    {isSubmitting ? 'Processing...' : 'Confirm Reservation'}
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </section>

      {/* Footer */}
      <footer className="footer-section">
        <div className="container">
          <div className="footer-content">
            <div className="footer-logo">
              <h3>D&S Creations</h3>
              <p>Your premier destination for cinema advertising solutions</p>
            </div>
            <div className="footer-links">
              <h4>Quick Links</h4>
              <ul>
                <li><a href="/">Home</a></li>
                <li><a href="/new-reservation">Book Slots</a></li>
                <li><a href="/my-reservations">My Reservations</a></li>
                <li><a href="/cinema-management">Manage Cinemas</a></li>
              </ul>
            </div>
            <div className="footer-contact">
              <h4>Contact Us</h4>
              <p>Email: info@dscreations.com</p>
              <p>Phone: +94 11 234 5678</p>
              <p>Address: Colombo, Sri Lanka</p>
            </div>
          </div>
          <div className="footer-bottom">
            <p>&copy; 2024 D&S Creations. All rights reserved.</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

export default NewReservation;
